import{_ as a,o as t,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Journeys Analytics","description":"","frontmatter":{"title":"Journeys Analytics","slug":"journeys-analytics"},"headers":[],"relativePath":"marketer-hub/journeys-analytics.md","filePath":"marketer-hub/journeys-analytics.md"}'),o={name:"marketer-hub/journeys-analytics.md"};function i(s,e,l,h,c,u){return t(),n("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Journeys Analytics is part of the legacy Branch experience.</p><p>Our new Branch Analysis tool offers customizable dashboards made up of flexible widgets to capture the data you need. Branch Analysis is being rolled out to customers in phases. While you&#39;re waiting for access, discover how to filter, share, and export performance across different channels on our <a href="https://help.branch.io/docs/branch-analysis" target="_blank" rel="noreferrer">Analysis Overview</a> page.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>To access Journeys analytics, click to <strong>Journeys</strong> from the navigation, click on the <strong>Activity</strong> tab to start analyzing your Journeys data. There are 2 visuals to use when analyzing your Journeys performance:</p><ul><li><a href="./journeys-analytics.html#trends">Trends using a graph view</a></li><li><a href="./journeys-analytics.html#performance">Performance using a table view</a></li></ul><p>We&#39;ll cover how to filter your data, using the Trends and Performance visuals, and some <a href="./journeys-analytics.html#tips-and-tricks">tips and tricks</a>.</p><div class="info custom-block"><p class="custom-block-title">Data Limits</p><p><strong>Cardinality Protection</strong></p><p>Branch limits all dimensions to 40,000 values per publisher per day. This means that you can only see up to 40,000 unique campaigns, ad names, etc in the Dashboard.</p><p>If an app tries to send up &gt; 40,000 values for a single dimension (e.g. ~campaign) in a day, then Branch stops tracking those unique values. Branch combines additional values together and bucket them under the value &quot;Other&quot;.</p></div><div class="danger custom-block"><p class="custom-block-title">Organic Check-Box Post iOS 14.5</p><p><strong>For</strong> <a href="./journeys-analytics.html#trends"><strong>Trends View</strong></a> <strong>and</strong> <a href="./journeys-analytics.html#performance"><strong>Performance View</strong></a><strong>:</strong>, the organic check-box will be removed because those views would be polluted with paid ad traffic which we cannot subtract from organic traffic due to those users never opting-in to tracking.</p><p>Having the organic check-box would introduce “Journeys vs Direct Traffic + Misattributed Paid Traffic”.</p><p>For additional information on changes post iOS 14.5, visit our <a href="./ios-14-faqs.html">FAQ Pages</a></p></div><h2 id="data-requirements" tabindex="-1">Data Requirements <a class="header-anchor" href="#data-requirements" aria-label="Permalink to &quot;Data Requirements&quot;">​</a></h2><h2 id="filtering-and-sharing-your-journeys-data" tabindex="-1">Filtering and Sharing Your Journeys Data <a class="header-anchor" href="#filtering-and-sharing-your-journeys-data" aria-label="Permalink to &quot;Filtering and Sharing Your Journeys Data&quot;">​</a></h2><p>At the top of the page, you&#39;ll see a menu of options that apply to both the Trends and Performance views. Here, you can set the date range you&#39;d like to see data for. This date range will apply to both the graph and table views on the page.</p><p>You can share your current dashboard view using the share button, which will preserve the filters and time windows; this is useful for circulating a specific set of filters among your team or with your Branch Technical Account Manager.</p><h2 id="trends" tabindex="-1">Trends <a class="header-anchor" href="#trends" aria-label="Permalink to &quot;Trends&quot;">​</a></h2><p>The Trends view is a visual breakdown of where your various in-app and web events are originating from the Journey banner. These events can be further filtered by the various analytics tags from their originating ad campaigns.</p><h3 id="common-analytics-labels" tabindex="-1">Common Analytics Labels <a class="header-anchor" href="#common-analytics-labels" aria-label="Permalink to &quot;Common Analytics Labels&quot;">​</a></h3><ol><li>CAMPAIGN: Auto-populated by the name of the Journey.</li><li>TAGS: Auto-populated by the name of the Journey view.</li><li>MOBILE PAGEVIEWS: This is a count of the number of page views your website has received for the date range.</li><li>JOURNEYS VIEWS: The total number of times the Journey banners were loaded and displayed on the webpage.</li><li>JOURNEYS DISMISSALS: A count of the number of times users dismissed Journeys.</li><li>REACH: This is the percentage of the web pages that are loading the Journeys banner on your website. The higher the number, the maximum installs you&#39;ll be driving.</li><li>VIEW TO CLICK: The ratio of the total number of times the banner was loaded and viewed on the webpage to the total number of times the users actually clicked on the banner.</li><li>VIEW TO OPEN: The ratio of the number of Journeys banners loaded and viewed on the webpage to the number of open events triggered in the app; this will include both the open events when the user clicks the banner or does an open event manually after seeing the banner on the web.</li></ol><p><strong>To get the performance of the banner, you can scroll down to the table below the graph:</strong></p><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>The Performance view is a table view that lets you see a more granular view of your event data. Here you can filter and compare fields with the same parameters as in the graph view, and see a side-by-side view of your events. Use the three vertical column button to select which events you&#39;d like to see in this table.</p><h2 id="tips-and-tricks" tabindex="-1">Tips and Tricks <a class="header-anchor" href="#tips-and-tricks" aria-label="Permalink to &quot;Tips and Tricks&quot;">​</a></h2><ul><li><p>You can export your current table view as a <em>CSV</em> file using the download button on the top right of the table.</p></li><li><p>The Unique checkbox on both the graph and table views allows you to restrict reports to one event of each type per user. For example, take a user who clicked an ad link, then opened the app seven times within the attribution window for that link. With the Unique box checked, we&#39;d report one of those opens, with it unchecked, we&#39;d report all seven.</p></li></ul><div class="info custom-block"><p class="custom-block-title">&quot;Unpopulated&quot; Ad Partner vs. &quot;Organic&quot;</p><p>There are times when Branch does not receive the name of the Ad Partner who received attribution. In these cases, the word <strong>Unpopulated</strong> will show as the name in the <strong>Ad Partner</strong> column.</p><p>For conversions that are not attributed to any Ad Partner, the word <strong>Organic</strong> will show in the <strong>Ad Partner</strong> column.</p></div>',21)])])}const m=a(o,[["render",i]]);export{p as __pageData,m as default};
